class Solution {
public:
    string countOfAtoms(string formula) {
        int n = formula.size();
        int i = 0;
        unordered_map<string, int> count;
        stack<pair<unordered_map<string, int>, int>> st;
        st.push({{}, 1});

        while (i < n) {
            if (formula[i] == '(') {
                st.push({{}, st.top().second});
                i++;
            } else if (formula[i] == ')') {
                i++;
                int num = 0;
                while (i < n && isdigit(formula[i])) {
                    num = num * 10 + (formula[i++] - '0');
                }
                if (num == 0) num = 1;
                auto top = st.top();
                st.pop();
                for (auto& [key, val] : top.first) {
                    count[key] += val * num;
                }
            } else {
                string name = "";
                name += formula[i++];
                while (i < n && islower(formula[i])) {
                    name += formula[i++];
                }
                int num = 0;
                while (i < n && isdigit(formula[i])) {
                    num = num * 10 + (formula[i++] - '0');
                }
                if (num == 0) num = 1;
                count[name] += num * st.top().second;
            }
        }

        string res = "";
        vector<pair<string, int>> vec;
        for (auto& [key, val] : count) {
            vec.push_back({key, val});
        }
        sort(vec.begin(), vec.end());
        for (auto& [key, val] : vec) {
            res += key;
            if (val > 1) {
                res += to_string(val);
            }
        }
        return res;
    }
};

